10	export function quote(customer: { yearsWithMHPCO: number }, items: Array<{ type: string; material: string; enchantment: number; cursed: boolean }>, contractIndex: number): number {
11	  const basePremium = items.reduce((sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0), 0);
12	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
13	  return basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
14	}
